inline const VAM *GetVAM(const void *buf) {
  return ::flatbuffers::GetRoot<VAM>(buf);
}

inline const VAM *GetSizePrefixedVAM(const void *buf) {
  return ::flatbuffers::GetSizePrefixedRoot<VAM>(buf);
}

inline const char *VAMIdentifier() {
  return "$VAM";
}

inline bool VAMBufferHasIdentifier(const void *buf) {
  return ::flatbuffers::BufferHasIdentifier(
      buf, VAMIdentifier());
}

inline bool SizePrefixedVAMBufferHasIdentifier(const void *buf) {
  return ::flatbuffers::BufferHasIdentifier(
      buf, VAMIdentifier(), true);
}

template <bool B = false>
inline bool VerifyVAMBuffer(
    ::flatbuffers::VerifierTemplate<B> &verifier) {
  return verifier.template VerifyBuffer<VAM>(VAMIdentifier());
}

template <bool B = false>
inline bool VerifySizePrefixedVAMBuffer(
    ::flatbuffers::VerifierTemplate<B> &verifier) {
  return verifier.template VerifySizePrefixedBuffer<VAM>(VAMIdentifier());
}

inline void FinishVAMBuffer(
    ::flatbuffers::FlatBufferBuilder &fbb,
    ::flatbuffers::Offset<VAM> root) {
  fbb.Finish(root, VAMIdentifier());
}

inline void FinishSizePrefixedVAMBuffer(
    ::flatbuffers::FlatBufferBuilder &fbb,
    ::flatbuffers::Offset<VAM> root) {
  fbb.FinishSizePrefixed(root, VAMIdentifier());
}

